  alert_wake: { bg:'„Събуди се"', ru:'«Проснулся»', uk:'«Прокинувся»', en:'“Woke up”', de:'„Aufgewacht"', fr:'« Réveillé »', es:'«Despertó»', 'es-MX':'«Despertó»', it:'«Sveglio»', pt:'“Acordou”', ar:'«استيقظ»', hi:'“जाग गया”', ja:'「起きた」', ky:'«Ойгонду»', 'zh-Hant':'「醒了」' },
  alert_stranger: { bg:'„Непознат в стаята" (втори човек)', ru:'«Незнакомец в комнате» (второй человек)', uk:'«Незнайомець у кімнаті» (друга людина)', en:'“Stranger in the room” (second person)', de:'„Fremder im Raum" (zweite Person)', fr:'« Inconnu dans la pièce » (deuxième personne)', es:'«Desconocido en la habitación» (segunda persona)', 'es-MX':'«Desconocido en la habitación» (segunda persona)', it:'«Sconosciuto nella stanza» (seconda persona)', pt:'“Estranho no quarto” (segunda pessoa)', ar:'«غريب في الغرفة» (شخص ثانٍ)', hi:'“कमरे में अजनबी” (दूसरा व्यक्ति)', ja:'「部屋に見知らぬ人」（2人目）', ky:'«Бөлмөдө бейтааныш» (экинчи адам)', 'zh-Hant':'「房間有陌生人」（第二人）' },
  alert_stranger_hint: { bg:'Само „появи се втори човек" — НЕ е разпознаване на лице или анти-отвличане.', ru:'Только «появился второй человек» — НЕ распознавание лица и не защита от похищения.', uk:'Лише «з’явилася друга людина» — НЕ розпізнавання обличчя й не захист від викрадення.', en:'Only “a second person appeared” — NOT face recognition or anti-abduction.', de:'Nur „eine zweite Person erschien" — KEINE Gesichtserkennung oder Entführungsschutz.', fr:'Seulement « une deuxième personne est apparue » — PAS de reconnaissance faciale ni d’anti-enlèvement.', es:'Solo «apareció una segunda persona» — NO es reconocimiento facial ni anti-secuestro.', 'es-MX':'Solo «apareció una segunda persona» — NO es reconocimiento facial ni anti-secuestro.', it:'Solo «è apparsa una seconda persona» — NON è riconoscimento facciale né anti-rapimento.', pt:'Apenas “apareceu uma segunda pessoa” — NÃO é reconhecimento facial nem antissequestro.', ar:'فقط «ظهر شخص ثانٍ» — ليس تعرّفًا على الوجه ولا مكافحة اختطاف.', hi:'केवल “दूसरा व्यक्ति दिखा” — चेहरा पहचान या अपहरण-रोधी नहीं।', ja:'「2人目が現れた」だけ — 顔認識や誘拐防止ではありません。', ky:'Болгону «экинчи адам пайда болду» — жүздү таануу же уурдоого каршы ЭМЕС.', 'zh-Hant':'僅「出現第二人」— 並非臉部辨識或防綁架。' },
  alert_left: { bg:'„Детето излезе от кадър"', ru:'«Ребёнок вышел из кадра»', uk:'«Дитина вийшла з кадру»', en:'“Child left the frame”', de:'„Kind hat das Bild verlassen"', fr:'« L’enfant a quitté le cadre »', es:'«El niño salió del encuadre»', 'es-MX':'«El niño salió del encuadre»', it:'«Il bambino è uscito dall’inquadratura»', pt:'“A criança saiu do quadro”', ar:'«خرج الطفل من الإطار»', hi:'“बच्चा फ़्रेम से बाहर गया”', ja:'「子どもがフレームから出た」', ky:'«Бала кадрдан чыкты»', 'zh-Hant':'「孩子離開畫面」' },
  alert_fire: { bg:'„Възможен пожар" (груба евристика)', ru:'«Возможен пожар» (грубая эвристика)', uk:'«Можлива пожежа» (груба евристика)', en:'“Possible fire” (rough heuristic)', de:'„Möglicher Brand" (grobe Heuristik)', fr:'« Incendie possible » (heuristique grossière)', es:'«Posible incendio» (heurística aproximada)', 'es-MX':'«Posible incendio» (heurística aproximada)', it:'«Possibile incendio» (euristica grossolana)', pt:'“Possível incêndio” (heurística grosseira)', ar:'«حريق محتمل» (تقدير تقريبي)', hi:'“संभावित आग” (मोटा अनुमान)', ja:'「火災の可能性」（粗い推定）', ky:'«Мүмкүн өрт» (одоно эвристика)', 'zh-Hant':'「可能起火」（粗略判斷）' },
  alert_fire_hint: { bg:'ГРУБА евристика по яркост/трептене — НЕ заменя датчик за дим! Изключено по подразбиране.', ru:'ГРУБАЯ эвристика по яркости/мерцанию — НЕ заменяет датчик дыма! Выключено по умолчанию.', uk:'ГРУБА евристика за яскравістю/мерехтінням — НЕ замінює датчик диму! Вимкнено за замовчуванням.', en:'A ROUGH brightness/flicker heuristic — does NOT replace a smoke detector! Off by default.', de:'Eine GROBE Helligkeits-/Flacker-Heuristik — ersetzt KEINEN Rauchmelder! Standardmäßig aus.', fr:'Heuristique GROSSIÈRE de luminosité/scintillement — ne remplace PAS un détecteur de fumée ! Désactivé par défaut.', es:'Heurística APROXIMADA de brillo/parpadeo — ¡NO sustituye un detector de humo! Desactivado por defecto.', 'es-MX':'Heurística APROXIMADA de brillo/parpadeo — ¡NO sustituye un detector de humo! Desactivado por defecto.', it:'Euristica GROSSOLANA di luminosità/sfarfallio — NON sostituisce un rilevatore di fumo! Disattivato di default.', pt:'Heurística GROSSEIRA de brilho/cintilação — NÃO substitui um detector de fumaça! Desativado por padrão.', ar:'تقدير تقريبي للسطوع/الوميض — لا يحلّ محلّ كاشف الدخان! معطّل افتراضيًا.', hi:'चमक/टिमटिमाहट का मोटा अनुमान — धुआँ सेंसर की जगह नहीं लेता! डिफ़ॉल्ट रूप से बंद।', ja:'明るさ/ちらつきの粗い推定 — 煙感知器の代わりにはなりません！既定でオフ。', ky:'Жарыктык/жымыңдоо боюнча ОДОНО эвристика — түтүн датчигин алмаштырбайт! Демейде өчүк.', 'zh-Hant':'亮度/閃爍的粗略判斷 — 不能取代煙霧偵測器！預設關閉。' },

