  evmsg_fire: { bg:'Възможен ярък блясък (ГРУБА евристика — НЕ е датчик за дим!).', ru:'Возможна яркая вспышка (ГРУБАЯ эвристика — НЕ датчик дыма!).', uk:'Можливий яскравий спалах (ГРУБА евристика — НЕ датчик диму!).', en:'Possible bright flare (ROUGH heuristic — NOT a smoke detector!).', de:'Möglicher heller Schein (GROBE Heuristik — KEIN Rauchmelder!).', fr:'Éclat lumineux possible (heuristique GROSSIÈRE — PAS un détecteur de fumée !).', es:'Posible destello brillante (heurística APROXIMADA — ¡NO es un detector de humo!).', 'es-MX':'Posible destello brillante (heurística APROXIMADA — ¡NO es un detector de humo!).', it:'Possibile bagliore intenso (euristica GROSSOLANA — NON è un rilevatore di fumo!).', pt:'Possível clarão intenso (heurística GROSSEIRA — NÃO é um detector de fumaça!).', ar:'وميض ساطع محتمل (تقدير تقريبي — ليس كاشف دخان!).', hi:'संभावित तेज़ चमक (मोटा अनुमान — धुआँ सेंसर नहीं!)।', ja:'明るい閃光の可能性（粗い推定 — 煙感知器ではありません！）。', ky:'Мүмкүн жаркыраган жарык (ОДОНО эвристика — түтүн датчиги ЭМЕС!).', 'zh-Hant':'可能的強光閃爍（粗略判斷 — 並非煙霧偵測器！）。' },
  evmsg_stranger: { bg:'Втори човек в стаята (непознат?).', ru:'Второй человек в комнате (незнакомец?).', uk:'Друга людина в кімнаті (незнайомець?).', en:'A second person in the room (a stranger?).', de:'Eine zweite Person im Raum (ein Fremder?).', fr:'Une deuxième personne dans la pièce (un inconnu ?).', es:'Una segunda persona en la habitación (¿un desconocido?).', 'es-MX':'Una segunda persona en la habitación (¿un desconocido?).', it:'Una seconda persona nella stanza (uno sconosciuto?).', pt:'Uma segunda pessoa no quarto (um estranho?).', ar:'شخص ثانٍ في الغرفة (غريب؟).', hi:'कमरे में दूसरा व्यक्ति (अजनबी?)।', ja:'部屋に2人目（見知らぬ人？）。', ky:'Бөлмөдө экинчи адам (бейтааныш?).', 'zh-Hant':'房間裡有第二人（陌生人？）。' },
  evmsg_left: { bg:'Детето излезе от кадър.', ru:'Ребёнок вышел из кадра.', uk:'Дитина вийшла з кадру.', en:'The child left the frame.', de:'Das Kind hat das Bild verlassen.', fr:'L’enfant a quitté le cadre.', es:'El niño salió del encuadre.', 'es-MX':'El niño salió del encuadre.', it:'Il bambino è uscito dall’inquadratura.', pt:'A criança saiu do quadro.', ar:'خرج الطفل من الإطار.', hi:'बच्चा फ़्रेम से बाहर चला गया।', ja:'子どもがフレームから出ました。', ky:'Бала кадрдан чыкты.', 'zh-Hant':'孩子離開了畫面。' },

